const item = $input.first().json;
const body = item.body || item;

const message = body.message || body.chatInput || '';
const sessionId = body.sessionId || '';
const conversationState = body.conversationState || {};
const pageUrl = body.pageUrl || '/';
const source = body.source || 'viltis-website';

const step = conversationState.step || 'start';
const leadData = conversationState.leadData || {};
const messageCount = conversationState.messageCount || 0;
const symptomChecklistDone = conversationState.symptomChecklistDone || false;
const portalRegistered = conversationState.portalRegistered || false;
const isReturning = step !== 'start' || Object.keys(leadData).length > 0 || messageCount > 0;

return [{
  json: {
    userMessage: message,
    sessionId,
    step,
    leadData,
    pageUrl,
    source,
    isReturning,
    messageCount,
    symptomChecklistDone,
    portalRegistered,
    conversationState
  }
}];

const data = $input.first().json;
const lead = data.leadData || {};

const historyLines = [];
if (lead.name) historyLines.push(`- Name: ${lead.name}`);
if (lead.email) historyLines.push(`- Email: ${lead.email}`);
if (lead.phone) historyLines.push(`- Phone: ${lead.phone}`);
if (lead.gender) historyLines.push(`- Gender pathway: ${lead.gender}`);
if (lead.state) historyLines.push(`- State: ${lead.state}`);
if (lead.symptoms?.length) historyLines.push(`- Symptoms noted: ${lead.symptoms.join(', ')}`);
if (lead.contactDeclined) {
  historyLines.push('- Contact: declined (support only — do NOT ask again)');
} else if (lead.name && lead.email) {
  historyLines.push('- Contact: complete (do NOT ask for name or email again)');
} else if (lead.name && !lead.email) {
  historyLines.push('- Contact: have name — ask for EMAIL ONLY if needed');
} else if (!lead.name && lead.email) {
  historyLines.push('- Contact: have email — ask for NAME ONLY if needed');
} else {
  historyLines.push('- Contact: not yet collected');
}
if (lead.symptomChecklistPrompted) historyLines.push('- Symptom checklist: already prompted');
if (lead.portalPrompted) historyLines.push('- Portal: already prompted');
if (lead.assistanceWith) {
  historyLines.push(`- Previous topic (only if visitor mentions it): ${lead.assistanceWith}`);
}
if (lead.topic && lead.topic !== lead.assistanceWith) {
  historyLines.push(`- Previous topic detail: ${lead.topic}`);
}
historyLines.push(`- Message count so far: ${data.messageCount || 0}`);

const priorHistory = historyLines.length > 0
  ? historyLines.join('\n')
  : 'No data collected yet';

return [{
  json: {
    userMessage: data.userMessage,
    sessionId: data.sessionId,
    step: data.step,
    leadData: lead,
    pageUrl: data.pageUrl || '/',
    source: data.source || 'viltis-website',
    messageCount: data.messageCount || 0,
    symptomChecklistDone: data.symptomChecklistDone || false,
    portalRegistered: data.portalRegistered || false,
    isReturning: true,
    systemContext: 'RETURNING_VISITOR',
    priorHistory
  }
}];

const data = $input.first().json;

let context = {};
try {
  context = $('Set New Visitor Context').first().json;
} catch (error) {
  try {
    context = $('Build Returning Context').first().json;
  } catch (innerError) {
    context = {};
  }
}

let raw = '';
try {
  raw = data.output[0].content[0].text;
} catch (error) {
  throw new Error('Could not read OpenAI response: ' + JSON.stringify(data));
}

if (!raw) {
  throw new Error('Empty response from OpenAI');
}

let clean = raw.trim();
if (clean.startsWith('```')) {
  clean = clean.replace(/^\`\`\`json?\n?/, '').replace(/\n?\`\`\`$/, '').trim();
}

let parsed;
try {
  parsed = JSON.parse(clean);
} catch (error) {
  parsed = {
    message: raw,
    nextStep: context.step || 'start',
    leadData: {},
    isHotLead: false,
    getStartedReady: false
  };
}

const existingLeadData = context.leadData || {};
const newLeadData = parsed.leadData || {};
const mergedLeadData = { ...existingLeadData };
const userMessage = (context.userMessage || '').trim();

Object.keys(newLeadData).forEach((key) => {
  const val = newLeadData[key];
  if (val !== '' && val !== null && val !== undefined) {
    mergedLeadData[key] = val;
  }
});

const refusalPattern = /\b(no thanks|not interested|don't want|do not want|prefer not|rather not|skip|without sharing|won't share|no email|pass on that|just browsing|not comfortable|won't give|i'd rather not|rather not share)\b/i;
if (refusalPattern.test(userMessage) && !(mergedLeadData.name && mergedLeadData.email)) {
  mergedLeadData.contactDeclined = true;
}

const topicDismissPattern = /\b(not looking for|not interested in|not today)\b/i;
if (topicDismissPattern.test(userMessage)) {
  if (newLeadData.topic) {
    mergedLeadData.topic = newLeadData.topic;
  } else {
    delete mergedLeadData.topic;
    delete mergedLeadData.assistanceWith;
  }
}

const topicChangePattern = /\b(not looking for|not interested in|instead|just need|want to know about|tell me about|what about|switch to|change to)\b/i;
if (topicChangePattern.test(userMessage) && newLeadData.topic) {
  mergedLeadData.topic = newLeadData.topic;
}
if (topicChangePattern.test(userMessage) && newLeadData.assistanceWith) {
  mergedLeadData.assistanceWith = newLeadData.assistanceWith;
}

const hasEmail = Boolean(mergedLeadData.email);
const hasName = Boolean(mergedLeadData.name);
const contactComplete = hasName && hasEmail;
const contactDeclined = Boolean(mergedLeadData.contactDeclined);
const previousStep = context.step || 'start';

let nextStep = parsed.nextStep || previousStep;
let getStartedReady = parsed.getStartedReady || false;

if (getStartedReady && !contactComplete) {
  getStartedReady = false;
}

if (contactComplete || contactDeclined || previousStep === 'completed') {
  nextStep = 'completed';
  getStartedReady = contactComplete;
}

if (nextStep === 'completed' && getStartedReady && !contactComplete) {
  getStartedReady = false;
}

const messageCount = Math.max(
  Number(parsed.messageCount) || 0,
  (context.messageCount || 0) + 1
);

const shouldSaveLead =
  getStartedReady &&
  contactComplete &&
  nextStep === 'completed' &&
  previousStep === 'collecting_contact';

function formatPlainText(text) {
  if (!text) return '';
  return text
    .replace(/^#{1,6}\s+/gm, '')
    .replace(/\*\*(.+?)\*\*/g, '$1')
    .replace(/__(.+?)__/g, '$1')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/^\s*[*-]\s+/gm, '• ')
    .replace(/(?<!\S)\*(?!\s)(.+?)(<!\S)\*(?!\S)/g, '$1')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function sanitizeContactAsk(message, lead, step) {
  let text = formatPlainText(message || '');
  const complete = Boolean(lead.name && lead.email);
  const declined = Boolean(lead.contactDeclined);

  if (complete || declined || step === 'completed') {
    return text
      .replace(/If you'd like,? share your (full )?name and email[^.!?]*[.!?]\s*/gi, '')
      .replace(/If you'd like,? share your email[^.!?]*[.!?]\s*/gi, '')
      .replace(/share your (full )?name and email[^.!?]*[.!?]\s*/gi, '')
      .replace(/could I get your (full )?name and email[^.!?]*[.!?]\s*/gi, '')
      .replace(/our team can follow up[^.!?]*[.!?]\s*/gi, '')
      .replace(/\n{3,}/g, '\n\n')
      .trim();
  }

  if (lead.name && !lead.email) {
    return text
      .replace(/name and email/gi, 'email')
      .replace(/your name and email/gi, 'your email')
      .replace(/full name and email/gi, 'email')
      .replace(/could I get your name[^.!?]*[.!?]\s*/gi, '')
      .trim();
  }

  if (!lead.name && lead.email) {
    return text
      .replace(/name and email/gi, 'name')
      .replace(/your name and email/gi, 'your name')
      .trim();
  }

  return text;
}

return [{
  json: {
    aiMessage: sanitizeContactAsk(parsed.message || '', mergedLeadData, nextStep),
    nextStep,
    leadData: mergedLeadData,
    isHotLead: parsed.isHotLead || false,
    getStartedReady,
    shouldSaveLead,
    messageCount,
    sessionId: context.sessionId || 'unknown-' + Date.now(),
    pageUrl: context.pageUrl || '/',
    source: context.source || 'viltis-website'
  }
}];

const data = $input.first().json;

return [{
  json: {
    response: data.aiMessage,
    getStartedUrl: data.getStartedReady ? 'https://portal.hrt.org/register' : null,
    conversationState: {
      step: data.nextStep,
      leadData: data.leadData || {},
      isHotLead: data.isHotLead || false,
      getStartedReady: data.getStartedReady || false,
      leadSaved: Boolean(data.shouldSaveLead) || false,
      messageCount: data.messageCount || 0,
      symptomChecklistDone: Boolean(data.leadData?.symptomChecklistPrompted) || false,
      portalRegistered: Boolean(data.leadData?.portalPrompted) || false
    },
    sessionId: data.sessionId || '',
    leadData: data.leadData || {},
    isHotLead: data.isHotLead || false,
    getStartedReady: data.getStartedReady || false,
    shouldSaveLead: data.shouldSaveLead || false,
    pageUrl: data.pageUrl || '/',
    source: data.source || 'viltis-website'
  }
}];
